evaluatorContext.idealResponse:
Design integration tests for the checkout flow:

INTEGRATION TESTING: Checkout Flow

---

COMPONENT INTERACTION MAP:

```
User Action Flow:

[Client] → [CheckoutController]
               |
               ├─→ [CartService] → [CartRepository]
               |
               ├─→ [CouponService] → [CouponRepository]
               |                   → [ExternalCouponAPI] (mock)
               |
               ├─→ [PaymentService] → [StripeAPI] (mock)
               |
               └─→ [OrderService] → [OrderRepository]
                                  → [InventoryService]
                                  → [EmailService] (mock)

Data Flow:
1. Cart items → Calculate totals
2. Apply coupon → Adjusted total
3. Process payment → Payment confirmation
4. Create order → Order record
5. Send confirmation → Email queued
```

---

MOCKING STRATEGY:

```yaml
mock_completely:
  StripeAPI:
    reason: "External service, don't want real charges in tests"
    mock_responses:
      - success: { paymentIntentId: 'pi_test_123', status: 'succeeded' }
      - decline: { error: { code: 'card_declined', message: 'Card was declined' } }
      - network_error: { throws: new Error('Network error') }

  EmailService:
    reason: "Don't send real emails, just verify calls"
    mock_type: "spy - verify called with correct args"

  ExternalCouponAPI:
    reason: "Third-party coupon validation"
    mock_responses:
      - valid: { valid: true, discount: 0.20 }
      - expired: { valid: false, reason: 'expired' }

use_real:
  CartRepository:
    reason: "Test real DB interactions"
    setup: "Use test database with known state"

  CouponRepository:
    reason: "Test coupon lookup logic"
    setup: "Seed test coupons in beforeEach"

  OrderRepository:
    reason: "Verify orders created correctly"
    setup: "Clean table before each test"

  InventoryService:
    reason: "Test inventory deduction"
    setup: "Seed products with known inventory"
```

---

TEST SCENARIOS:

```yaml
happy_path:
  scenario_1_simple_checkout:
    setup:
      - Cart with 2 items (total: $50)
      - User logged in
      - Valid payment method
    steps:
      - Add items to cart
      - Proceed to checkout
      - Enter payment details
      - Submit order
    assertions:
      - Order created in database
      - Order status: 'confirmed'
      - Payment intent succeeded
      - Inventory decremented
      - Confirmation email queued

  scenario_2_with_coupon:
    setup:
      - Cart with items (total: $100)
      - Valid coupon: SAVE20 (20% off)
    steps:
      - Add items to cart
      - Apply coupon SAVE20
      - Proceed to checkout
      - Submit order
    assertions:
      - Discount applied: $20
      - Final charge: $80
      - Coupon marked as used
      - Order has coupon reference

  scenario_3_guest_checkout:
    setup:
      - Not logged in
      - Cart with items
    steps:
      - Checkout as guest with email
      - Enter payment
      - Submit
    assertions:
      - Order created without user_id
      - Guest email stored on order
      - Confirmation sent to guest email

error_scenarios:
  payment_declined:
    setup:
      - Valid cart
      - Stripe mock returns: card_declined
    assertions:
      - Order NOT created
      - Cart preserved
      - Error message: 'Payment declined'
      - Inventory NOT decremented

  payment_network_error:
    setup:
      - Valid cart
      - Stripe mock throws network error
    assertions:
      - Order NOT created
      - Error message: 'Payment processing failed'
      - User can retry

  invalid_coupon:
    setup:
      - Valid cart
      - Coupon mock returns: expired
    assertions:
      - Coupon not applied
      - Error message: 'Coupon is expired'
      - Can continue without coupon

  out_of_stock:
    setup:
      - Cart with item
      - Inventory: 0 (depleted between cart add and checkout)
    assertions:
      - Order NOT created
      - Payment NOT attempted
      - Error message: 'Item out of stock'
      - Cart updated to show unavailable

  partial_stock:
    setup:
      - Cart: 5 items
      - Inventory: 3 available
    assertions:
      - Choice offered: proceed with 3 or cancel
      - If proceed: order for 3, cart cleared
      - If cancel: cart preserved

edge_cases:
  concurrent_checkout:
    setup:
      - Two users, same item, inventory: 1
    test:
      - Both attempt checkout simultaneously
    assertions:
      - One succeeds, one fails
      - No overselling
      - Proper error for loser

  cart_modification_during_checkout:
    setup:
      - User starts checkout
      - Cart modified in another tab
    assertions:
      - Detect cart change
      - Require confirmation or recalculate
```

---

TEST IMPLEMENTATION STRUCTURE:

```typescript
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { createTestDb, cleanupTestDb } from '../test-utils/database';
import { createMockStripe } from '../test-utils/stripe-mock';
import { CheckoutController } from './CheckoutController';

describe('Checkout Integration', () => {
  let db: TestDatabase;
  let stripeMock: MockStripe;
  let controller: CheckoutController;

  beforeEach(async () => {
    db = await createTestDb();
    stripeMock = createMockStripe();
    controller = new CheckoutController({
      db,
      stripe: stripeMock,
      emailService: vi.fn(),
    });

    // Seed test data
    await db.products.insert(testProducts);
    await db.coupons.insert(testCoupons);
  });

  afterEach(async () => {
    await cleanupTestDb(db);
  });

  describe('Happy Path', () => {
    it('completes simple checkout successfully', async () => {
      // Arrange
      stripeMock.paymentIntents.create.mockResolvedValue({
        id: 'pi_test',
        status: 'succeeded',
      });

      const cart = await createTestCart(db, [
        { productId: 'prod-1', quantity: 2 },
      ]);

      // Act
      const result = await controller.checkout({
        cartId: cart.id,
        paymentMethodId: 'pm_test',
        email: 'test@example.com',
      });

      // Assert
      expect(result.success).toBe(true);
      expect(result.orderId).toBeDefined();

      const order = await db.orders.findById(result.orderId);
      expect(order.status).toBe('confirmed');
      expect(order.total).toBe(cart.total);

      const inventory = await db.products.getInventory('prod-1');
      expect(inventory).toBe(initialInventory - 2);
    });
  });

  describe('Payment Failures', () => {
    it('handles declined card gracefully', async () => {
      // Arrange
      stripeMock.paymentIntents.create.mockRejectedValue({
        code: 'card_declined',
        message: 'Your card was declined',
      });

      const cart = await createTestCart(db, [{ productId: 'prod-1', quantity: 1 }]);

      // Act
      const result = await controller.checkout({
        cartId: cart.id,
        paymentMethodId: 'pm_test',
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('Your card was declined');

      // Verify no order created
      const orders = await db.orders.findByCartId(cart.id);
      expect(orders).toHaveLength(0);

      // Verify cart still exists
      const cartAfter = await db.carts.findById(cart.id);
      expect(cartAfter).not.toBeNull();
    });
  });
});
```
